package tests

import (
	"context"
	"testing"
	"time"

	"github.com/entire-io/e2e-tests/testutil"
	"github.com/stretchr/testify/assert"
)

// TestLineAttributionReasonable: agent creates a file, attribution metadata
// should reflect that agent wrote most/all of the content.
// Bug #344: attribution metadata is significantly off for simple agent-created content.
func TestLineAttributionReasonable(t *testing.T) {
	testutil.SkipKnownIssue(t, "ENT-344", "line attribution blows up for simple agent content")

	testutil.ForEachAgent(t, 3*time.Minute, func(t *testing.T, s *testutil.RepoState, ctx context.Context) {
		_, err := s.RunPrompt(t, ctx,
			"create a single markdown file at docs/example.md with a few paragraphs about software testing")
		if err != nil {
			t.Fatalf("agent failed: %v", err)
		}
		testutil.AssertFileExists(t, s.Dir, "docs/example.md")

		s.Git(t, "add", "docs/")
		s.Git(t, "commit", "-m", "Add example.md")

		testutil.WaitForCheckpoint(t, s, 15*time.Second)

		cpID := testutil.AssertHasCheckpointTrailer(t, s.Dir, "HEAD")
		sm := testutil.ReadSessionMetadata(t, s.Dir, cpID, 0)

		assert.Greater(t, sm.InitialAttribution.AgentLines, 0,
			"agent lines should be > 0")
		assert.Greater(t, sm.InitialAttribution.TotalCommitted, 0,
			"total committed should be > 0")
		assert.Greater(t, sm.InitialAttribution.AgentPercentage, 50.0,
			"agent created 100%% of content, percentage should be > 50%%")
	})
}

//go:build integration

package integration

import (
	"encoding/json"
	"testing"

	"github.com/entireio/cli/cmd/entire/cli/checkpoint"
	"github.com/entireio/cli/cmd/entire/cli/checkpoint/id"
	"github.com/entireio/cli/cmd/entire/cli/paths"
	"github.com/entireio/cli/cmd/entire/cli/strategy"
	"github.com/entireio/cli/cmd/entire/cli/trailers"
	"github.com/go-git/go-git/v5"
	"github.com/go-git/go-git/v5/plumbing"
)

// TestManualCommit_Attribution tests the full attribution calculation flow:
// 1. Agent creates checkpoint 1
// 2. User makes changes between checkpoints
// 3. User enters new prompt (attribution calculated at prompt start)
// 4. Agent creates checkpoint 2
// 5. User commits (condensation happens with attribution)
// 6. Verify attribution metadata is correct
func TestManualCommit_Attribution(t *testing.T) {
	t.Parallel()
	env := NewTestEnv(t)
	defer env.Cleanup()

	env.InitRepo()

	// Create initial commit
	env.WriteFile("main.go", "package main\n")
	env.GitAdd("main.go")
	env.GitCommit("Initial commit")

	env.InitEntire(strategy.StrategyNameManualCommit)

	initialHead := env.GetHeadHash()
	t.Logf("Initial HEAD: %s", initialHead[:7])

	// ========================================
	// CHECKPOINT 1: Agent adds function
	// ========================================
	t.Log("Creating checkpoint 1 (agent adds function)")

	session := env.NewSession()
	if err := env.SimulateUserPromptSubmit(session.ID); err != nil {
		t.Fatalf("SimulateUserPromptSubmit (prompt 1) failed: %v", err)
	}

	// Agent adds 4 lines
	checkpoint1Content := "package main\n\nfunc agentFunc() {\n\treturn 42\n}\n"
	env.WriteFile("main.go", checkpoint1Content)

	session.CreateTranscript(
		"Add agent function",
		[]FileChange{{Path: "main.go", Content: checkpoint1Content}},
	)
	if err := env.SimulateStop(session.ID, session.TranscriptPath); err != nil {
		t.Fatalf("SimulateStop (checkpoint 1) failed: %v", err)
	}

	// ========================================
	// USER EDITS between checkpoints
	// ========================================
	t.Log("User makes edits between checkpoints")

	// User adds 5 comment lines
	userContent := checkpoint1Content +
		"// User comment 1\n" +
		"// User comment 2\n" +
		"// User comment 3\n" +
		"// User comment 4\n" +
		"// User comment 5\n"
	env.WriteFile("main.go", userContent)

	// ========================================
	// CHECKPOINT 2: New prompt (attribution calculated)
	// ========================================
	t.Log("User enters new prompt (attribution should capture 5 user lines)")

	// Simulate UserPromptSubmit hook - this calculates attribution at prompt start
	if err := env.SimulateUserPromptSubmit(session.ID); err != nil {
		t.Fatalf("SimulateUserPromptSubmit (prompt 2) failed: %v", err)
	}

	// Agent adds another function (4 more lines)
	checkpoint2Content := userContent + "\nfunc agentFunc2() {\n\treturn 100\n}\n"
	env.WriteFile("main.go", checkpoint2Content)

	session.CreateTranscript(
		"Add second agent function",
		[]FileChange{{Path: "main.go", Content: checkpoint2Content}},
	)
	if err := env.SimulateStop(session.ID, session.TranscriptPath); err != nil {
		t.Fatalf("SimulateStop (checkpoint 2) failed: %v", err)
	}

	// Verify 2 rewind points
	points := env.GetRewindPoints()
	if len(points) != 2 {
		t.Fatalf("Expected 2 rewind points, got %d", len(points))
	}

	// ========================================
	// USER COMMITS: Condensation happens
	// ========================================
	t.Log("User commits (condensation should happen)")

	// Commit using hooks (this triggers condensation)
	env.GitCommitWithShadowHooks("Add functions", "main.go")

	// Get commit hash and checkpoint ID
	headHash := env.GetHeadHash()
	t.Logf("User commit: %s", headHash[:7])

	repo, err := git.PlainOpen(env.RepoDir)
	if err != nil {
		t.Fatalf("failed to open repo: %v", err)
	}

	commitObj, err := repo.CommitObject(plumbing.NewHash(headHash))
	if err != nil {
		t.Fatalf("failed to get commit object: %v", err)
	}

	checkpointID, found := trailers.ParseCheckpoint(commitObj.Message)
	if !found {
		t.Fatal("Commit should have Entire-Checkpoint trailer")
	}
	t.Logf("Checkpoint ID: %s", checkpointID)

	// ========================================
	// VERIFY ATTRIBUTION
	// ========================================
	t.Log("Verifying attribution in metadata")

	// Read metadata from entire/checkpoints/v1 branch
	sessionsRef, err := repo.Reference(plumbing.NewBranchReferenceName(paths.MetadataBranchName), true)
	if err != nil {
		t.Fatalf("Failed to get entire/checkpoints/v1 branch: %v", err)
	}

	sessionsCommit, err := repo.CommitObject(sessionsRef.Hash())
	if err != nil {
		t.Fatalf("Failed to get sessions commit: %v", err)
	}

	sessionsTree, err := sessionsCommit.Tree()
	if err != nil {
		t.Fatalf("Failed to get sessions tree: %v", err)
	}

	// Read session-level metadata.json from sharded path (InitialAttribution is in 0/metadata.json)
	metadataPath := SessionMetadataPath(checkpointID.String())
	metadataFile, err := sessionsTree.File(metadataPath)
	if err != nil {
		t.Fatalf("Failed to read session metadata.json at path %s: %v", metadataPath, err)
	}

	metadataContent, err := metadataFile.Contents()
	if err != nil {
		t.Fatalf("Failed to read metadata content: %v", err)
	}

	var metadata checkpoint.CommittedMetadata
	if err := json.Unmarshal([]byte(metadataContent), &metadata); err != nil {
		t.Fatalf("Failed to parse metadata.json: %v", err)
	}

	// Verify InitialAttribution exists
	if metadata.InitialAttribution == nil {
		t.Fatal("InitialAttribution is nil")
	}

	attr := metadata.InitialAttribution
	t.Logf("Attribution: agent=%d, human_added=%d, human_modified=%d, human_removed=%d, total=%d, percentage=%.1f%%",
		attr.AgentLines, attr.HumanAdded, attr.HumanModified, attr.HumanRemoved,
		attr.TotalCommitted, attr.AgentPercentage)

	// Verify attribution was calculated and has reasonable values
	// Note: The shadow branch includes all worktree changes (agent + user),
	// so base→shadow diff includes user edits that were present during SaveChanges.
	// The attribution separates them using PromptAttributions.
	//
	// Expected: agent=13 (base→shadow includes user comments in worktree)
	//           human=5 (from PromptAttribution)
	//           total=18 (net additions)
	//
	// This tests that:
	// 1. Attribution is calculated and stored
	// 2. PromptAttribution captured user edits between checkpoints
	// 3. Percentages are computed
	if attr.AgentLines <= 0 {
		t.Errorf("AgentLines = %d, should be > 0", attr.AgentLines)
	}

	if attr.HumanAdded != 5 {
		t.Errorf("HumanAdded = %d, want 5 (5 comments captured in PromptAttribution)",
			attr.HumanAdded)
	}

	if attr.TotalCommitted <= 0 {
		t.Errorf("TotalCommitted = %d, should be > 0", attr.TotalCommitted)
	}

	if attr.AgentPercentage <= 0 || attr.AgentPercentage >= 100 {
		t.Errorf("AgentPercentage = %.1f%%, should be between 0 and 100",
			attr.AgentPercentage)
	}
}

// TestManualCommit_AttributionDeletionOnly tests attribution for deletion-only commits
func TestManualCommit_AttributionDeletionOnly(t *testing.T) {
	t.Parallel()
	env := NewTestEnv(t)
	defer env.Cleanup()

	env.InitRepo()

	// Create initial commit with content
	initialContent := "package main\n\nfunc oldFunc1() {}\nfunc oldFunc2() {}\nfunc oldFunc3() {}\n"
	env.WriteFile("main.go", initialContent)
	env.GitAdd("main.go")
	env.GitCommit("Initial commit")

	env.InitEntire(strategy.StrategyNameManualCommit)

	// ========================================
	// CHECKPOINT 1: Agent REMOVES a function (deletion, no additions)
	// ========================================
	session := env.NewSession()
	if err := env.SimulateUserPromptSubmit(session.ID); err != nil {
		t.Fatalf("SimulateUserPromptSubmit failed: %v", err)
	}

	// Agent removes one function (keeps 2 functions)
	checkpointContent := "package main\n\nfunc oldFunc2() {}\nfunc oldFunc3() {}\n"
	env.WriteFile("main.go", checkpointContent)

	session.CreateTranscript(
		"Remove oldFunc1",
		[]FileChange{{Path: "main.go", Content: checkpointContent}},
	)
	if err := env.SimulateStop(session.ID, session.TranscriptPath); err != nil {
		t.Fatalf("SimulateStop failed: %v", err)
	}

	// ========================================
	// USER DELETES REMAINING FUNCTIONS
	// ========================================
	t.Log("User deletes remaining functions (deletion-only commit)")

	// Remove remaining functions, keep only package declaration
	env.WriteFile("main.go", "package main\n")

	// Commit using hooks
	env.GitCommitWithShadowHooks("Remove remaining functions", "main.go")

	// Get checkpoint ID
	headHash := env.GetHeadHash()
	repo, err := git.PlainOpen(env.RepoDir)
	if err != nil {
		t.Fatalf("failed to open repo: %v", err)
	}

	commitObj, err := repo.CommitObject(plumbing.NewHash(headHash))
	if err != nil {
		t.Fatalf("failed to get commit object: %v", err)
	}

	checkpointID, found := trailers.ParseCheckpoint(commitObj.Message)
	if !found {
		t.Fatal("Commit should have Entire-Checkpoint trailer")
	}

	// ========================================
	// VERIFY ATTRIBUTION FOR DELETION-ONLY COMMIT
	// ========================================
	t.Log("Verifying attribution for deletion-only commit")

	sessionsRef, err := repo.Reference(plumbing.NewBranchReferenceName(paths.MetadataBranchName), true)
	if err != nil {
		t.Fatalf("Failed to get entire/checkpoints/v1 branch: %v", err)
	}

	sessionsCommit, err := repo.CommitObject(sessionsRef.Hash())
	if err != nil {
		t.Fatalf("Failed to get sessions commit: %v", err)
	}

	sessionsTree, err := sessionsCommit.Tree()
	if err != nil {
		t.Fatalf("Failed to get sessions tree: %v", err)
	}

	// Read session-level metadata.json (InitialAttribution is in 0/metadata.json)
	metadataPath := SessionMetadataPath(checkpointID.String())
	metadataFile, err := sessionsTree.File(metadataPath)
	if err != nil {
		t.Fatalf("Failed to read session metadata.json at path %s: %v", metadataPath, err)
	}

	metadataContent, err := metadataFile.Contents()
	if err != nil {
		t.Fatalf("Failed to read metadata content: %v", err)
	}

	var metadata checkpoint.CommittedMetadata
	if err := json.Unmarshal([]byte(metadataContent), &metadata); err != nil {
		t.Fatalf("Failed to parse metadata.json: %v", err)
	}

	if metadata.InitialAttribution == nil {
		t.Fatal("InitialAttribution is nil")
	}

	attr := metadata.InitialAttribution
	t.Logf("Attribution (deletion-only): agent=%d, human_added=%d, human_removed=%d, total=%d, percentage=%.1f%%",
		attr.AgentLines, attr.HumanAdded, attr.HumanRemoved,
		attr.TotalCommitted, attr.AgentPercentage)

	// For deletion-only commits where agent makes no additions:
	// - Agent removed oldFunc1 (made deletions, not additions)
	// - AgentLines = 0 (no additions)
	// - User removed oldFunc2 and oldFunc3
	// - HumanAdded = 0 (no new lines)
	// - HumanRemoved = number of lines user deleted
	// - TotalCommitted = 0 (no additions from anyone)
	// - AgentPercentage = 0 (by convention for deletion-only)

	if attr.AgentLines != 0 {
		t.Errorf("AgentLines = %d, want 0 (agent made no additions, only deletions)", attr.AgentLines)
	}

	if attr.HumanAdded != 0 {
		t.Errorf("HumanAdded = %d, want 0 (no new lines in deletion-only commit)", attr.HumanAdded)
	}

	// User removed 2 remaining functions + 1 blank line (3 lines total)
	if attr.HumanRemoved != 3 {
		t.Errorf("HumanRemoved = %d, want 3 (removed blank + 2 functions = 3 lines)", attr.HumanRemoved)
	}

	if attr.TotalCommitted != 0 {
		t.Errorf("TotalCommitted = %d, want 0 (deletion-only commit has no net additions)", attr.TotalCommitted)
	}

	if attr.AgentPercentage != 0 {
		t.Errorf("AgentPercentage = %.1f%%, want 0 (deletion-only commit)",
			attr.AgentPercentage)
	}
}

// TestManualCommit_AttributionNoDoubleCount tests that PromptAttributions are
// cleared after condensation to prevent double-counting on subsequent commits.
//
// Bug scenario:
// 1. Checkpoint 1 → user edits → commit (condensation, PromptAttributions used)
// 2. StepCount reset to 0, but PromptAttributions NOT cleared
// 3. Checkpoint 2 → new PromptAttributions appended to old ones
// 4. Second commit → CalculateAttributionWithAccumulated sums ALL PromptAttributions
// 5. User edits from first commit are double-counted
func TestManualCommit_AttributionNoDoubleCount(t *testing.T) {
	t.Parallel()
	env := NewTestEnv(t)
	defer env.Cleanup()

	env.InitRepo()

	// Create initial commit
	env.WriteFile("main.go", "package main\n")
	env.GitAdd("main.go")
	env.GitCommit("Initial commit")

	env.InitEntire(strategy.StrategyNameManualCommit)

	// ========================================
	// FIRST CYCLE: Checkpoint → user edit → commit
	// ========================================
	t.Log("First cycle: agent checkpoint + user edit + commit")

	session := env.NewSession()
	if err := env.SimulateUserPromptSubmit(session.ID); err != nil {
		t.Fatalf("SimulateUserPromptSubmit (first cycle) failed: %v", err)
	}

	// Agent adds 5 lines
	checkpoint1Content := "package main\n\nfunc agent1() { return 1 }\nfunc agent2() { return 2 }\nfunc agent3() { return 3 }\n"
	env.WriteFile("main.go", checkpoint1Content)

	session.CreateTranscript(
		"Add agent functions",
		[]FileChange{{Path: "main.go", Content: checkpoint1Content}},
	)
	if err := env.SimulateStop(session.ID, session.TranscriptPath); err != nil {
		t.Fatalf("SimulateStop (first cycle) failed: %v", err)
	}

	// User adds 2 lines between checkpoints
	userEdit1Content := checkpoint1Content + "// User comment 1\n// User comment 2\n"
	env.WriteFile("main.go", userEdit1Content)

	// Commit with hooks (condensation happens)
	env.GitCommitWithShadowHooks("First commit", "main.go")

	// Get first commit's checkpoint ID
	repo, err := git.PlainOpen(env.RepoDir)
	if err != nil {
		t.Fatalf("failed to open repo: %v", err)
	}

	head, err := repo.Head()
	if err != nil {
		t.Fatalf("failed to get HEAD: %v", err)
	}

	commit1, err := repo.CommitObject(head.Hash())
	if err != nil {
		t.Fatalf("failed to get commit: %v", err)
	}

	checkpointID1, found := trailers.ParseCheckpoint(commit1.Message)
	if !found {
		t.Fatal("First commit should have checkpoint trailer")
	}

	t.Logf("First commit checkpoint ID: %s", checkpointID1)

	// Verify first commit attribution
	attr1 := getAttributionFromMetadata(t, repo, checkpointID1)
	t.Logf("First commit attribution: agent=%d, human_added=%d, total=%d",
		attr1.AgentLines, attr1.HumanAdded, attr1.TotalCommitted)

	// First commit should have:
	// - Agent: 4 lines (3 functions + 1 blank)
	// - User: 2 lines (2 comments)
	// - Total: 6 lines
	if attr1.HumanAdded != 2 {
		t.Errorf("First commit HumanAdded = %d, want 2", attr1.HumanAdded)
	}

	// ========================================
	// SECOND CYCLE: New checkpoint → user edit → commit
	// ========================================
	t.Log("Second cycle: new agent checkpoint + user edit + commit")

	// Simulate new prompt (should calculate attribution, which should be empty after reset)
	if err := env.SimulateUserPromptSubmit(session.ID); err != nil {
		t.Fatalf("SimulateUserPromptSubmit (second cycle) failed: %v", err)
	}

	// Agent adds 3 more lines
	checkpoint2Content := userEdit1Content + "\nfunc agent4() { return 4 }\nfunc agent5() { return 5 }\n"
	env.WriteFile("main.go", checkpoint2Content)

	session.CreateTranscript(
		"Add more agent functions",
		[]FileChange{{Path: "main.go", Content: checkpoint2Content}},
	)
	if err := env.SimulateStop(session.ID, session.TranscriptPath); err != nil {
		t.Fatalf("SimulateStop (second cycle) failed: %v", err)
	}

	// User adds 1 more line
	userEdit2Content := checkpoint2Content + "// User comment 3\n"
	env.WriteFile("main.go", userEdit2Content)

	// Second commit (another condensation)
	env.GitCommitWithShadowHooks("Second commit", "main.go")

	// Get second commit's checkpoint ID
	head, err = repo.Head()
	if err != nil {
		t.Fatalf("failed to get HEAD after second commit: %v", err)
	}

	commit2, err := repo.CommitObject(head.Hash())
	if err != nil {
		t.Fatalf("failed to get second commit: %v", err)
	}

	checkpointID2, found := trailers.ParseCheckpoint(commit2.Message)
	if !found {
		t.Fatal("Second commit should have checkpoint trailer")
	}

	t.Logf("Second commit checkpoint ID: %s", checkpointID2)

	// Verify second commit attribution
	attr2 := getAttributionFromMetadata(t, repo, checkpointID2)
	t.Logf("Second commit attribution: agent=%d, human_added=%d, total=%d",
		attr2.AgentLines, attr2.HumanAdded, attr2.TotalCommitted)

	// Second commit should have (since first commit):
	// - Agent: 3 lines (2 functions + 1 blank)
	// - User: 1 line (1 comment)
	// - Total: 4 lines
	//
	// BUG (if not fixed): HumanAdded would be 3 (1 new + 2 from first commit double-counted)
	// CORRECT (after fix): HumanAdded should be 1 (only new user edits)

	if attr2.HumanAdded != 1 {
		t.Errorf("Second commit HumanAdded = %d, want 1 (should NOT double-count first commit's 2 user lines)",
			attr2.HumanAdded)
	}

	if attr2.TotalCommitted != 4 {
		t.Errorf("Second commit TotalCommitted = %d, want 4 (3 agent + 1 user)",
			attr2.TotalCommitted)
	}

	// Agent percentage should be 3/4 = 75%
	if attr2.AgentPercentage < 74.9 || attr2.AgentPercentage > 75.1 {
		t.Errorf("Second commit AgentPercentage = %.1f%%, want 75.0%%", attr2.AgentPercentage)
	}
}

// getAttributionFromMetadata reads attribution from a checkpoint on entire/checkpoints/v1 branch.
// InitialAttribution is stored in session-level metadata (0/metadata.json).
func getAttributionFromMetadata(t *testing.T, repo *git.Repository, checkpointID id.CheckpointID) *checkpoint.InitialAttribution {
	t.Helper()

	sessionsRef, err := repo.Reference(plumbing.NewBranchReferenceName(paths.MetadataBranchName), true)
	if err != nil {
		t.Fatalf("Failed to get entire/checkpoints/v1 branch: %v", err)
	}

	sessionsCommit, err := repo.CommitObject(sessionsRef.Hash())
	if err != nil {
		t.Fatalf("Failed to get sessions commit: %v", err)
	}

	sessionsTree, err := sessionsCommit.Tree()
	if err != nil {
		t.Fatalf("Failed to get sessions tree: %v", err)
	}

	// Read session-level metadata (InitialAttribution is in 0/metadata.json)
	metadataPath := SessionMetadataPath(checkpointID.String())
	metadataFile, err := sessionsTree.File(metadataPath)
	if err != nil {
		t.Fatalf("Failed to read session metadata.json at path %s: %v", metadataPath, err)
	}

	metadataContent, err := metadataFile.Contents()
	if err != nil {
		t.Fatalf("Failed to read metadata content: %v", err)
	}

	var metadata checkpoint.CommittedMetadata
	if err := json.Unmarshal([]byte(metadataContent), &metadata); err != nil {
		t.Fatalf("Failed to parse metadata.json: %v", err)
	}

	if metadata.InitialAttribution == nil {
		t.Fatal("InitialAttribution is nil")
	}

	return metadata.InitialAttribution
}

package strategy

import (
	"slices"
	"strings"
	"time"

	"github.com/entireio/cli/cmd/entire/cli/checkpoint"
	"github.com/go-git/go-git/v5/plumbing/object"
	"github.com/sergi/go-diff/diffmatchpatch"
)

// getAllChangedFilesBetweenTrees returns a list of all files that differ between two trees.
// This includes files that were added, modified, or deleted in either tree.
// Uses git blob hashes for efficient comparison without reading file contents.
func getAllChangedFilesBetweenTrees(tree1, tree2 *object.Tree) []string {
	if tree1 == nil && tree2 == nil {
		return nil
	}

	// Build hash maps for each tree - O(n) iteration, no content reading
	tree1Hashes := make(map[string]string)
	tree2Hashes := make(map[string]string)

	if tree1 != nil {
		//nolint:errcheck // Errors ignored - just collecting file hashes for diff comparison
		_ = tree1.Files().ForEach(func(f *object.File) error {
			tree1Hashes[f.Name] = f.Hash.String()
			return nil
		})
	}

	if tree2 != nil {
		//nolint:errcheck // Errors ignored - just collecting file hashes for diff comparison
		_ = tree2.Files().ForEach(func(f *object.File) error {
			tree2Hashes[f.Name] = f.Hash.String()
			return nil
		})
	}

	// Find changed files by comparing hashes (much faster than content comparison)
	var changed []string

	// Check files in tree1 - either modified or deleted in tree2
	for path, hash1 := range tree1Hashes {
		if hash2, exists := tree2Hashes[path]; !exists || hash1 != hash2 {
			changed = append(changed, path)
		}
	}

	// Check files only in tree2 (added files)
	for path := range tree2Hashes {
		if _, exists := tree1Hashes[path]; !exists {
			changed = append(changed, path)
		}
	}

	return changed
}

// getFileContent retrieves the content of a file from a tree.
// Returns empty string if the file doesn't exist, can't be read, or is a binary file.
//
// Binary files are silently excluded from attribution calculations because line-based
// diffing doesn't apply to binary content. This means binary files (images, compiled
// binaries, etc.) won't appear in attribution metrics even if they were added or modified.
// This is intentional - attribution measures code contributions via line counting,
// which only makes sense for text files.
//
// Uses go-git's IsBinary() which implements git's binary detection algorithm.
//
// TODO: Consider tracking binary file counts separately (e.g., BinaryFilesChanged field)
// to provide visibility into non-text file modifications.
func getFileContent(tree *object.Tree, path string) string {
	if tree == nil {
		return ""
	}

	file, err := tree.File(path)
	if err != nil {
		return ""
	}

	// Use git's binary detection algorithm
	isBinary, err := file.IsBinary()
	if err != nil || isBinary {
		return ""
	}

	content, err := file.Contents()
	if err != nil {
		return ""
	}

	return content
}

// diffLines compares two strings and returns line-level diff stats.
// Returns (unchanged, added, removed) line counts.
func diffLines(checkpointContent, committedContent string) (unchanged, added, removed int) {
	// Handle edge cases
	if checkpointContent == committedContent {
		return countLinesStr(committedContent), 0, 0
	}
	if checkpointContent == "" {
		return 0, countLinesStr(committedContent), 0
	}
	if committedContent == "" {
		return 0, 0, countLinesStr(checkpointContent)
	}

	dmp := diffmatchpatch.New()

	// Convert to line-based diff using DiffLinesToChars/DiffCharsToLines pattern
	text1, text2, lineArray := dmp.DiffLinesToChars(checkpointContent, committedContent)
	diffs := dmp.DiffMain(text1, text2, false)
	diffs = dmp.DiffCharsToLines(diffs, lineArray)

	for _, d := range diffs {
		lines := countLinesStr(d.Text)
		switch d.Type {
		case diffmatchpatch.DiffEqual:
			unchanged += lines
		case diffmatchpatch.DiffInsert:
			added += lines
		case diffmatchpatch.DiffDelete:
			removed += lines
		}
	}

	return unchanged, added, removed
}

// countLinesStr returns the number of lines in a string.
// An empty string has 0 lines. A string without newlines has 1 line.
// This is used for both file content and diff text segments.
func countLinesStr(content string) int {
	if content == "" {
		return 0
	}
	lines := strings.Count(content, "\n")
	// If content doesn't end with newline, add 1 for the last line
	if !strings.HasSuffix(content, "\n") {
		lines++
	}
	return lines
}

// CalculateAttributionWithAccumulated computes final attribution using accumulated prompt data.
// This provides more accurate attribution than tree-only comparison because it captures
// user edits that happened between checkpoints (which would otherwise be mixed into the
// checkpoint snapshots).
//
// The calculation:
// 1. Sum user edits from PromptAttributions (captured at each prompt start)
// 2. Add user edits after the final checkpoint (shadow → head diff)
// 3. Calculate agent lines from base → shadow
// 4. Estimate user self-modifications vs agent modifications using per-file tracking
// 5. Compute percentages
//
// Note: Binary files (detected by null bytes) are silently excluded from attribution
// calculations since line-based diffing only applies to text files.
//
// See docs/architecture/attribution.md for details on the per-file tracking approach.
func CalculateAttributionWithAccumulated(
	baseTree *object.Tree,
	shadowTree *object.Tree,
	headTree *object.Tree,
	filesTouched []string,
	promptAttributions []PromptAttribution,
) *checkpoint.InitialAttribution {
	if len(filesTouched) == 0 {
		return nil
	}

	// Sum accumulated user lines from prompt attributions
	// Also aggregate per-file user additions for accurate modification tracking
	var accumulatedUserAdded, accumulatedUserRemoved int
	accumulatedUserAddedPerFile := make(map[string]int)
	for _, pa := range promptAttributions {
		accumulatedUserAdded += pa.UserLinesAdded
		accumulatedUserRemoved += pa.UserLinesRemoved
		// Merge per-file data from all prompt attributions
		for filePath, added := range pa.UserAddedPerFile {
			accumulatedUserAddedPerFile[filePath] += added
		}
	}

	// Calculate attribution for agent-touched files
	// IMPORTANT: shadowTree is a snapshot of the worktree at checkpoint time,
	// which includes both agent work AND accumulated user edits (to agent-touched files).
	// So base→shadow diff = (agent work + accumulated user work to these files).
	var totalAgentAndUserWork int
	var postCheckpointUserAdded, postCheckpointUserRemoved int
	postCheckpointUserRemovedPerFile := make(map[string]int)

	for _, filePath := range filesTouched {
		baseContent := getFileContent(baseTree, filePath)
		shadowContent := getFileContent(shadowTree, filePath)
		headContent := getFileContent(headTree, filePath)

		// Total work in shadow: base → shadow (agent + accumulated user work for this file)
		_, workAdded, _ := diffLines(baseContent, shadowContent)
		totalAgentAndUserWork += workAdded

		// Post-checkpoint user edits: shadow → head (only post-checkpoint edits for this file)
		_, postUserAdded, postUserRemoved := diffLines(shadowContent, headContent)
		postCheckpointUserAdded += postUserAdded
		postCheckpointUserRemoved += postUserRemoved

		// Track per-file removals for self-modification estimation
		if postUserRemoved > 0 {
			postCheckpointUserRemovedPerFile[filePath] = postUserRemoved
		}
	}

	// Calculate total user edits to non-agent files (files not in filesTouched)
	// These files are not in the shadow tree, so base→head captures ALL their user edits
	nonAgentFiles := getAllChangedFilesBetweenTrees(baseTree, headTree)
	var allUserEditsToNonAgentFiles int
	for _, filePath := range nonAgentFiles {
		if slices.Contains(filesTouched, filePath) {
			continue // Skip agent-touched files
		}

		baseContent := getFileContent(baseTree, filePath)
		headContent := getFileContent(headTree, filePath)
		_, userAdded, _ := diffLines(baseContent, headContent)
		allUserEditsToNonAgentFiles += userAdded
	}

	// Separate accumulated edits by file type using per-file tracking data.
	// This is precise because accumulatedUserAddedPerFile tells us exactly which files
	// the user edited between checkpoints.
	var accumulatedToAgentFiles, accumulatedToNonAgentFiles int
	for filePath, added := range accumulatedUserAddedPerFile {
		if slices.Contains(filesTouched, filePath) {
			accumulatedToAgentFiles += added
		} else {
			accumulatedToNonAgentFiles += added
		}
	}

	// Agent work = (base→shadow for agent files) - (accumulated user edits to agent files only)
	totalAgentAdded := max(0, totalAgentAndUserWork-accumulatedToAgentFiles)

	// Post-checkpoint edits to non-agent files = total edits - accumulated portion (never negative)
	postToNonAgentFiles := max(0, allUserEditsToNonAgentFiles-accumulatedToNonAgentFiles)

	// Total user contribution = accumulated (all files) + post-checkpoint (agent files) + post-checkpoint (non-agent files)
	totalUserAdded := accumulatedUserAdded + postCheckpointUserAdded + postToNonAgentFiles
	totalUserRemoved := accumulatedUserRemoved + postCheckpointUserRemoved

	// Estimate modified lines (user changed existing lines)
	// Lines that were both added and removed are treated as modifications.
	totalHumanModified := min(totalUserAdded, totalUserRemoved)

	// Estimate user self-modifications using per-file tracking (see docs/architecture/attribution.md)
	// When a user removes lines from a file, assume they're removing their own lines first (LIFO).
	// Only after exhausting their own additions should we count removals as targeting agent lines.
	userSelfModified := estimateUserSelfModifications(accumulatedUserAddedPerFile, postCheckpointUserRemovedPerFile)

	// humanModifiedAgent = modifications that targeted agent lines (not user's own lines)
	humanModifiedAgent := max(0, totalHumanModified-userSelfModified)

	// Remaining modifications are user self-modifications (user edited their own code)
	// These should NOT be subtracted from agent lines
	pureUserAdded := totalUserAdded - totalHumanModified
	pureUserRemoved := totalUserRemoved - totalHumanModified

	// Total net additions = agent additions + pure user additions - pure user removals
	// This reconstructs the base → head diff from our tracked changes.
	// Note: This measures "net new lines added to the codebase" not total file size.
	// pureUserRemoved represents agent lines that the user deleted, so we subtract them.
	totalCommitted := totalAgentAdded + pureUserAdded - pureUserRemoved
	if totalCommitted <= 0 {
		// Fallback for delete-only commits or when removals exceed additions
		// Note: If both are 0 (deletion-only commit where agent added nothing),
		// totalCommitted will be 0 and percentage will be 0. This is expected -
		// the attribution percentage is only meaningful for commits that add code.
		totalCommitted = max(0, totalAgentAdded)
	}

	// Calculate agent lines actually in the commit (excluding removed and modified)
	// Agent added lines, but user removed some and modified others.
	// Only subtract modifications that targeted AGENT lines (humanModifiedAgent),
	// not user self-modifications.
	// Clamp to 0 to handle cases where user removed/modified more than agent added.
	agentLinesInCommit := max(0, totalAgentAdded-pureUserRemoved-humanModifiedAgent)

	// Calculate percentage
	var agentPercentage float64
	if totalCommitted > 0 {
		agentPercentage = float64(agentLinesInCommit) / float64(totalCommitted) * 100
	}

	return &checkpoint.InitialAttribution{
		CalculatedAt:    time.Now().UTC(),
		AgentLines:      agentLinesInCommit,
		HumanAdded:      pureUserAdded,
		HumanModified:   totalHumanModified, // Total modifications (for reporting)
		HumanRemoved:    pureUserRemoved,
		TotalCommitted:  totalCommitted,
		AgentPercentage: agentPercentage,
	}
}

// estimateUserSelfModifications estimates how many removed lines were the user's own additions.
// Uses LIFO assumption: when a user removes lines from a file, they likely remove their own
// recent additions before touching agent lines.
//
// See docs/architecture/attribution.md for the rationale behind this heuristic.
func estimateUserSelfModifications(
	accumulatedUserAddedPerFile map[string]int,
	postCheckpointUserRemovedPerFile map[string]int,
) int {
	var selfModified int
	for filePath, removed := range postCheckpointUserRemovedPerFile {
		userAddedToFile := accumulatedUserAddedPerFile[filePath]
		// User can only self-modify up to what they previously added
		selfModified += min(removed, userAddedToFile)
	}
	return selfModified
}

// CalculatePromptAttribution computes line-level attribution at the start of a prompt.
// This captures user edits since the last checkpoint BEFORE the agent makes changes.
//
// Parameters:
//   - baseTree: the tree at session start (the base commit)
//   - lastCheckpointTree: the tree from the previous checkpoint (nil if first checkpoint)
//   - worktreeFiles: map of file path → current worktree content for files that changed
//   - checkpointNumber: which checkpoint we're about to create (1-indexed)
//
// Returns the attribution data to store in session state. For checkpoint 1 (when
// lastCheckpointTree is nil), AgentLinesAdded/Removed will be 0 since there's no
// previous checkpoint to measure cumulative agent work against.
//
// Note: Binary files (detected by null bytes) in reference trees are silently excluded
// from attribution calculations since line-based diffing only applies to text files.
func CalculatePromptAttribution(
	baseTree *object.Tree,
	lastCheckpointTree *object.Tree,
	worktreeFiles map[string]string,
	checkpointNumber int,
) PromptAttribution {
	result := PromptAttribution{
		CheckpointNumber: checkpointNumber,
		UserAddedPerFile: make(map[string]int),
	}

	if len(worktreeFiles) == 0 {
		return result
	}

	// Determine reference tree for user changes (last checkpoint or base)
	referenceTree := lastCheckpointTree
	if referenceTree == nil {
		referenceTree = baseTree
	}

	for filePath, worktreeContent := range worktreeFiles {
		referenceContent := getFileContent(referenceTree, filePath)
		baseContent := getFileContent(baseTree, filePath)

		// User changes: diff(reference, worktree)
		// These are changes since the last checkpoint that the agent didn't make
		_, userAdded, userRemoved := diffLines(referenceContent, worktreeContent)
		result.UserLinesAdded += userAdded
		result.UserLinesRemoved += userRemoved

		// Track per-file user additions for accurate modification tracking.
		// This enables distinguishing user self-modifications from agent modifications.
		if userAdded > 0 {
			result.UserAddedPerFile[filePath] = userAdded
		}

		// Agent lines so far: diff(base, lastCheckpoint)
		// Only calculate if we have a previous checkpoint
		if lastCheckpointTree != nil {
			checkpointContent := getFileContent(lastCheckpointTree, filePath)
			_, agentAdded, agentRemoved := diffLines(baseContent, checkpointContent)
			result.AgentLinesAdded += agentAdded
			result.AgentLinesRemoved += agentRemoved
		}
	}

	return result
}

// Package checkpoint provides types and interfaces for checkpoint storage.
//
// A Checkpoint captures a point-in-time within a session, containing either
// full state (Temporary) or metadata with a commit reference (Committed).
//
// See docs/architecture/sessions-and-checkpoints.md for the full domain model.
package checkpoint

import (
	"context"
	"errors"
	"time"

	"github.com/entireio/cli/cmd/entire/cli/agent"
	"github.com/entireio/cli/cmd/entire/cli/checkpoint/id"

	"github.com/go-git/go-git/v5/plumbing"
)

// Errors returned by checkpoint operations.
var (
	// ErrCheckpointNotFound is returned when a checkpoint ID doesn't exist.
	ErrCheckpointNotFound = errors.New("checkpoint not found")

	// ErrNoTranscript is returned when a checkpoint exists but has no transcript.
	ErrNoTranscript = errors.New("no transcript found for checkpoint")
)

// Checkpoint represents a save point within a session.
type Checkpoint struct {
	// ID is the unique checkpoint identifier
	ID string

	// SessionID is the session this checkpoint belongs to
	SessionID string

	// Timestamp is when this checkpoint was created
	Timestamp time.Time

	// Type indicates temporary (full state) or committed (metadata only)
	Type Type

	// Message is a human-readable description of the checkpoint
	Message string
}

// Type indicates the storage location and lifecycle of a checkpoint.
type Type int

const (
	// Temporary checkpoints contain full state (code + metadata) and are stored
	// on shadow branches (entire/<commit-hash>). Used for intra-session rewind.
	Temporary Type = iota

	// Committed checkpoints contain metadata + commit reference and are stored
	// on the entire/checkpoints/v1 branch. They are the permanent record.
	Committed
)

// Store provides low-level primitives for reading and writing checkpoints.
// This is used by strategies to implement their storage approach.
//
// The interface matches the GitStore implementation signatures directly:
// - WriteTemporary takes WriteTemporaryOptions and returns a result with commit hash and skip status
// - ReadTemporary takes baseCommit (not sessionID) since shadow branches are keyed by commit
// - List methods return implementation-specific info types for richer data
type Store interface {
	// WriteTemporary writes a temporary checkpoint (full state) to a shadow branch.
	// Shadow branches are named entire/<base-commit-short-hash>.
	// Returns a result containing the commit hash and whether the checkpoint was skipped.
	// Checkpoints are skipped (deduplicated) when the tree hash matches the previous checkpoint.
	WriteTemporary(ctx context.Context, opts WriteTemporaryOptions) (WriteTemporaryResult, error)

	// ReadTemporary reads the latest checkpoint from a shadow branch.
	// baseCommit is the commit hash the session is based on.
	// worktreeID is the internal git worktree identifier (empty for main worktree).
	// Returns nil, nil if the shadow branch doesn't exist.
	ReadTemporary(ctx context.Context, baseCommit, worktreeID string) (*ReadTemporaryResult, error)

	// ListTemporary lists all shadow branches with their checkpoint info.
	ListTemporary(ctx context.Context) ([]TemporaryInfo, error)

	// WriteCommitted writes a committed checkpoint to the entire/checkpoints/v1 branch.
	// Checkpoints are stored at sharded paths: <id[:2]>/<id[2:]>/
	WriteCommitted(ctx context.Context, opts WriteCommittedOptions) error

	// ReadCommitted reads a committed checkpoint's summary by ID.
	// Returns only the CheckpointSummary (paths + aggregated stats), not actual content.
	// Use ReadSessionContent to read actual transcript/prompts/context.
	// Returns nil, nil if the checkpoint does not exist.
	ReadCommitted(ctx context.Context, checkpointID id.CheckpointID) (*CheckpointSummary, error)

	// ReadSessionContent reads the actual content for a specific session within a checkpoint.
	// sessionIndex is 0-based (0 for first session, 1 for second, etc.).
	// Returns the session's metadata, transcript, prompts, and context.
	ReadSessionContent(ctx context.Context, checkpointID id.CheckpointID, sessionIndex int) (*SessionContent, error)

	// ReadSessionContentByID reads a session's content by its session ID.
	// Useful when you have the session ID but don't know its index within the checkpoint.
	ReadSessionContentByID(ctx context.Context, checkpointID id.CheckpointID, sessionID string) (*SessionContent, error)

	// ListCommitted lists all committed checkpoints.
	ListCommitted(ctx context.Context) ([]CommittedInfo, error)

	// UpdateCommitted replaces the transcript, prompts, and context for an existing
	// committed checkpoint. Used at stop time to finalize checkpoints with the full
	// session transcript (prompt to stop event).
	// Returns ErrCheckpointNotFound if the checkpoint doesn't exist.
	UpdateCommitted(ctx context.Context, opts UpdateCommittedOptions) error
}

// WriteTemporaryResult contains the result of writing a temporary checkpoint.
type WriteTemporaryResult struct {
	// CommitHash is the hash of the created or existing checkpoint commit
	CommitHash plumbing.Hash

	// Skipped is true if the checkpoint was skipped due to no changes
	// (tree hash matched the previous checkpoint)
	Skipped bool
}

// WriteTemporaryOptions contains options for writing a temporary checkpoint.
type WriteTemporaryOptions struct {
	// SessionID is the session identifier
	SessionID string

	// BaseCommit is the commit hash this session is based on
	BaseCommit string

	// WorktreeID is the internal git worktree identifier (empty for main worktree)
	// Used to create worktree-specific shadow branch names
	WorktreeID string

	// ModifiedFiles are files that have been modified (relative paths)
	ModifiedFiles []string

	// NewFiles are files that have been created (relative paths)
	NewFiles []string

	// DeletedFiles are files that have been deleted (relative paths)
	DeletedFiles []string

	// MetadataDir is the relative path to the metadata directory
	MetadataDir string

	// MetadataDirAbs is the absolute path to the metadata directory
	MetadataDirAbs string

	// CommitMessage is the commit subject line
	CommitMessage string

	// AuthorName is the name to use for commits
	AuthorName string

	// AuthorEmail is the email to use for commits
	AuthorEmail string

	// IsFirstCheckpoint indicates if this is the first checkpoint of the session
	// When true, all working directory files are captured (not just modified)
	IsFirstCheckpoint bool
}

// ReadTemporaryResult contains the result of reading a temporary checkpoint.
type ReadTemporaryResult struct {
	// CommitHash is the hash of the checkpoint commit
	CommitHash plumbing.Hash

	// TreeHash is the hash of the tree containing the checkpoint state
	TreeHash plumbing.Hash

	// SessionID is the session identifier from the commit trailer
	SessionID string

	// MetadataDir is the metadata directory path from the commit trailer
	MetadataDir string

	// Timestamp is when the checkpoint was created
	Timestamp time.Time
}

// TemporaryInfo contains summary information about a shadow branch.
type TemporaryInfo struct {
	// BranchName is the full branch name (e.g., "entire/abc1234")
	BranchName string

	// BaseCommit is the short commit hash this branch is based on
	BaseCommit string

	// LatestCommit is the hash of the latest commit on the branch
	LatestCommit plumbing.Hash

	// SessionID is the session identifier from the latest commit
	SessionID string

	// Timestamp is when the latest checkpoint was created
	Timestamp time.Time
}

// WriteCommittedOptions contains options for writing a committed checkpoint.
type WriteCommittedOptions struct {
	// CheckpointID is the stable 12-hex-char identifier
	CheckpointID id.CheckpointID

	// SessionID is the session identifier
	SessionID string

	// Strategy is the name of the strategy that created this checkpoint
	Strategy string

	// Branch is the branch name where the checkpoint was created (empty if detached HEAD)
	Branch string

	// Transcript is the session transcript content (full.jsonl)
	Transcript []byte

	// Prompts contains user prompts from the session
	Prompts []string

	// Context is the generated context.md content
	Context []byte

	// FilesTouched are files modified during the session
	FilesTouched []string

	// CheckpointsCount is the number of checkpoints in this session
	CheckpointsCount int

	// EphemeralBranch is the shadow branch name (for manual-commit strategy)
	EphemeralBranch string

	// AuthorName is the name to use for commits
	AuthorName string

	// AuthorEmail is the email to use for commits
	AuthorEmail string

	// MetadataDir is a directory containing additional metadata files to copy
	// If set, all files in this directory will be copied to the checkpoint path
	// This is useful for copying task metadata files, subagent transcripts, etc.
	MetadataDir string

	// Task checkpoint fields (for auto-commit strategy task checkpoints)
	IsTask    bool   // Whether this is a task checkpoint
	ToolUseID string // Tool use ID for task checkpoints

	// Additional task checkpoint fields for subagent checkpoints
	AgentID                string // Subagent identifier
	CheckpointUUID         string // UUID for transcript truncation when rewinding
	TranscriptPath         string // Path to session transcript file (alternative to in-memory Transcript)
	SubagentTranscriptPath string // Path to subagent's transcript file

	// Incremental checkpoint fields
	IsIncremental       bool   // Whether this is an incremental checkpoint
	IncrementalSequence int    // Checkpoint sequence number
	IncrementalType     string // Tool type that triggered this checkpoint
	IncrementalData     []byte // Tool input payload for this checkpoint

	// Commit message fields (used for task checkpoints)
	CommitSubject string // Subject line for the metadata commit (overrides default)

	// Agent identifies the agent that created this checkpoint (e.g., "Claude Code", "Cursor")
	Agent agent.AgentType

	// TurnID correlates checkpoints from the same agent turn.
	TurnID string

	// Transcript position at checkpoint start - tracks what was added during this checkpoint
	TranscriptIdentifierAtStart string // Last identifier when checkpoint started (UUID for Claude, message ID for Gemini)
	CheckpointTranscriptStart   int    // Transcript line offset at start of this checkpoint's data

	// CheckpointTranscriptStart is written to both CommittedMetadata.CheckpointTranscriptStart
	// and the deprecated CommittedMetadata.TranscriptLinesAtStart for backward compatibility.

	// TokenUsage contains the token usage for this checkpoint
	TokenUsage *agent.TokenUsage

	// InitialAttribution is line-level attribution calculated at commit time
	// comparing checkpoint tree (agent work) to committed tree (may include human edits)
	InitialAttribution *InitialAttribution

	// Summary is an optional AI-generated summary for this checkpoint.
	// This field may be nil when:
	//   - summarization is disabled in settings
	//   - summary generation failed (non-blocking, logged as warning)
	//   - the transcript was empty or too short to summarize
	//   - the checkpoint predates the summarization feature
	Summary *Summary

	// SessionTranscriptPath is the home-relative path to the session transcript file.
	// Persisted in CommittedMetadata so restore can write the transcript back to
	// the correct location without reconstructing agent-specific paths.
	SessionTranscriptPath string
}

// UpdateCommittedOptions contains options for updating an existing committed checkpoint.
// Uses replace semantics: the transcript, prompts, and context are fully replaced,
// not appended. At stop time we have the complete session transcript and want every
// checkpoint to contain it identically.
type UpdateCommittedOptions struct {
	// CheckpointID identifies the checkpoint to update
	CheckpointID id.CheckpointID

	// SessionID identifies which session slot to update within the checkpoint
	SessionID string

	// Transcript is the full session transcript (replaces existing)
	Transcript []byte

	// Prompts contains all user prompts (replaces existing)
	Prompts []string

	// Context is the updated context.md content (replaces existing)
	Context []byte

	// Agent identifies the agent type (needed for transcript chunking)
	Agent agent.AgentType
}

// CommittedInfo contains summary information about a committed checkpoint.
type CommittedInfo struct {
	// CheckpointID is the stable 12-hex-char identifier
	CheckpointID id.CheckpointID

	// SessionID is the session identifier (most recent session for multi-session checkpoints)
	SessionID string

	// CreatedAt is when the checkpoint was created
	CreatedAt time.Time

	// CheckpointsCount is the total number of checkpoints across all sessions
	CheckpointsCount int

	// FilesTouched are files modified during all sessions
	FilesTouched []string

	// Agent identifies the agent that created this checkpoint
	Agent agent.AgentType

	// IsTask indicates if this is a task checkpoint
	IsTask bool

	// ToolUseID is the tool use ID for task checkpoints
	ToolUseID string

	// Multi-session support
	SessionCount int      // Number of sessions (1 if single session)
	SessionIDs   []string // All session IDs that contributed
}

// SessionContent contains the actual content for a session.
// This is used when reading full session data (transcript, prompts, context)
// as opposed to just the metadata/summary.
type SessionContent struct {
	// Metadata contains the session-specific metadata
	Metadata CommittedMetadata

	// Transcript is the session transcript content
	Transcript []byte

	// Prompts contains user prompts from this session
	Prompts string

	// Context is the context.md content
	Context string
}

// CommittedMetadata contains the metadata stored in metadata.json for each checkpoint.
type CommittedMetadata struct {
	CLIVersion       string          `json:"cli_version,omitempty"`
	CheckpointID     id.CheckpointID `json:"checkpoint_id"`
	SessionID        string          `json:"session_id"`
	Strategy         string          `json:"strategy"`
	CreatedAt        time.Time       `json:"created_at"`
	Branch           string          `json:"branch,omitempty"` // Branch where checkpoint was created (empty if detached HEAD)
	CheckpointsCount int             `json:"checkpoints_count"`
	FilesTouched     []string        `json:"files_touched"`

	// Agent identifies the agent that created this checkpoint (e.g., "Claude Code", "Cursor")
	Agent agent.AgentType `json:"agent,omitempty"`

	// TurnID correlates checkpoints from the same agent turn.
	// When a turn's work spans multiple commits, each gets its own checkpoint
	// but they share the same TurnID for future aggregation/deduplication.
	TurnID string `json:"turn_id,omitempty"`

	// Task checkpoint fields (only populated for task checkpoints)
	IsTask    bool   `json:"is_task,omitempty"`
	ToolUseID string `json:"tool_use_id,omitempty"`

	// Transcript position at checkpoint start - tracks what was added during this checkpoint
	TranscriptIdentifierAtStart string `json:"transcript_identifier_at_start,omitempty"` // Last identifier when checkpoint started (UUID for Claude, message ID for Gemini)
	CheckpointTranscriptStart   int    `json:"checkpoint_transcript_start,omitempty"`    // Transcript line offset at start of this checkpoint's data

	// Deprecated: Use CheckpointTranscriptStart instead. Written for backward compatibility with older CLI versions.
	TranscriptLinesAtStart int `json:"transcript_lines_at_start,omitempty"`

	// Token usage for this checkpoint
	TokenUsage *agent.TokenUsage `json:"token_usage,omitempty"`

	// AI-generated summary of the checkpoint
	Summary *Summary `json:"summary,omitempty"`

	// InitialAttribution is line-level attribution calculated at commit time
	InitialAttribution *InitialAttribution `json:"initial_attribution,omitempty"`

	// TranscriptPath is the home-relative path to the session transcript file.
	// Persisted so restore can write the transcript back to the correct location
	// without needing to reconstruct agent-specific paths (e.g. SHA-256 hashed dirs for Gemini).
	TranscriptPath string `json:"transcript_path,omitempty"`
}

// GetTranscriptStart returns the transcript line offset at which this checkpoint's data begins.
// Returns 0 for new checkpoints (start from beginning). For data written by older CLI versions,
// falls back to the deprecated TranscriptLinesAtStart field.
func (m CommittedMetadata) GetTranscriptStart() int {
	if m.CheckpointTranscriptStart > 0 {
		return m.CheckpointTranscriptStart
	}
	return m.TranscriptLinesAtStart
}

// SessionFilePaths contains the absolute paths to session files from the git tree root.
// Paths include the full checkpoint path prefix (e.g., "/a1/b2c3d4e5f6/1/metadata.json").
// Used in CheckpointSummary.Sessions to map session IDs to their file locations.
type SessionFilePaths struct {
	Metadata    string `json:"metadata"`
	Transcript  string `json:"transcript"`
	Context     string `json:"context"`
	ContentHash string `json:"content_hash"`
	Prompt      string `json:"prompt"`
}

// CheckpointSummary is the root-level metadata.json for a checkpoint.
// It contains aggregated statistics from all sessions and a map of session IDs
// to their file paths. Session-specific data (including initial_attribution)
// is stored in the session's subdirectory metadata.json.
//
// Structure on entire/checkpoints/v1 branch:
//
//	<checkpoint-id[:2]>/<checkpoint-id[2:]>/
//	├── metadata.json         # This CheckpointSummary
//	├── 1/                    # First session
//	│   ├── metadata.json     # Session-specific CommittedMetadata
//	│   ├── full.jsonl
//	│   ├── prompt.txt
//	│   ├── context.md
//	│   └── content_hash.txt
//	├── 2/                    # Second session
//	└── 3/                    # Third session...
//
//nolint:revive // Named CheckpointSummary to avoid conflict with existing Summary struct
type CheckpointSummary struct {
	CLIVersion       string             `json:"cli_version,omitempty"`
	CheckpointID     id.CheckpointID    `json:"checkpoint_id"`
	Strategy         string             `json:"strategy"`
	Branch           string             `json:"branch,omitempty"`
	CheckpointsCount int                `json:"checkpoints_count"`
	FilesTouched     []string           `json:"files_touched"`
	Sessions         []SessionFilePaths `json:"sessions"`
	TokenUsage       *agent.TokenUsage  `json:"token_usage,omitempty"`
}

// Summary contains AI-generated summary of a checkpoint.
type Summary struct {
	Intent    string           `json:"intent"`     // What user wanted to accomplish
	Outcome   string           `json:"outcome"`    // What was achieved
	Learnings LearningsSummary `json:"learnings"`  // Categorized learnings
	Friction  []string         `json:"friction"`   // Problems/annoyances encountered
	OpenItems []string         `json:"open_items"` // Tech debt, unfinished work
}

// LearningsSummary contains learnings grouped by scope.
type LearningsSummary struct {
	Repo     []string       `json:"repo"`     // Codebase-specific patterns/conventions
	Code     []CodeLearning `json:"code"`     // File/module specific findings
	Workflow []string       `json:"workflow"` // General dev practices
}

// CodeLearning captures a learning tied to a specific code location.
type CodeLearning struct {
	Path    string `json:"path"`               // File path
	Line    int    `json:"line,omitempty"`     // Start line number
	EndLine int    `json:"end_line,omitempty"` // End line for ranges (optional)
	Finding string `json:"finding"`            // What was learned
}

// InitialAttribution captures line-level attribution metrics at commit time.
// This is a point-in-time snapshot comparing the checkpoint tree (agent work)
// against the committed tree (may include human edits).
//
// Attribution Metrics:
//   - TotalCommitted measures "net additions" (lines added that remain in the commit)
//   - AgentPercentage represents "of the new code added, what percentage came from the agent"
//   - Deletion work is tracked separately in HumanRemoved (not included in percentage)
//
// Deletion-Only Commits:
// For commits with only deletions (no additions), TotalCommitted will be 0 and
// AgentPercentage will be 0. This is by design - the percentage metric is only
// meaningful for commits that add code. Deletion contributions are captured in
// the HumanRemoved field but don't affect the attribution percentage.
type InitialAttribution struct {
	CalculatedAt    time.Time `json:"calculated_at"`
	AgentLines      int       `json:"agent_lines"`      // Lines added by agent (base → shadow diff)
	HumanAdded      int       `json:"human_added"`      // Lines added by human (excluding modifications)
	HumanModified   int       `json:"human_modified"`   // Lines modified by human (estimate: min(added, removed))
	HumanRemoved    int       `json:"human_removed"`    // Lines removed by human (excluding modifications)
	TotalCommitted  int       `json:"total_committed"`  // Net additions in commit (agent + human new lines, not total file size)
	AgentPercentage float64   `json:"agent_percentage"` // agent_lines / total_committed * 100 (0 for deletion-only commits)
}

// Info provides summary information for listing checkpoints.
// This is the generic checkpoint info type.
type Info struct {
	// ID is the checkpoint identifier
	ID string

	// SessionID identifies the session
	SessionID string

	// Type indicates temporary or committed
	Type Type

	// CreatedAt is when the checkpoint was created
	CreatedAt time.Time

	// Message is a summary description
	Message string
}

// WriteTemporaryTaskOptions contains options for writing a task checkpoint.
// Task checkpoints are created when a subagent completes and contain both
// code changes and task-specific metadata.
type WriteTemporaryTaskOptions struct {
	// SessionID is the session identifier
	SessionID string

	// BaseCommit is the commit hash this session is based on
	BaseCommit string

	// WorktreeID is the internal git worktree identifier (empty for main worktree)
	// Used to create worktree-specific shadow branch names
	WorktreeID string

	// ToolUseID is the unique identifier for this Task tool invocation
	ToolUseID string

	// AgentID is the subagent identifier
	AgentID string

	// ModifiedFiles are files that have been modified (relative paths)
	ModifiedFiles []string

	// NewFiles are files that have been created (relative paths)
	NewFiles []string

	// DeletedFiles are files that have been deleted (relative paths)
	DeletedFiles []string

	// TranscriptPath is the path to the main session transcript
	TranscriptPath string

	// SubagentTranscriptPath is the path to the subagent's transcript
	SubagentTranscriptPath string

	// CheckpointUUID is the UUID for transcript truncation when rewinding
	CheckpointUUID string

	// CommitMessage is the commit message (already formatted)
	CommitMessage string

	// AuthorName is the name to use for commits
	AuthorName string

	// AuthorEmail is the email to use for commits
	AuthorEmail string

	// IsIncremental indicates this is an incremental checkpoint
	IsIncremental bool

	// IncrementalSequence is the checkpoint sequence number
	IncrementalSequence int

	// IncrementalType is the tool that triggered this checkpoint
	IncrementalType string

	// IncrementalData is the tool_input payload for this checkpoint
	IncrementalData []byte
}

// TemporaryCheckpointInfo contains information about a single commit on a shadow branch.
// Used by ListTemporaryCheckpoints to provide rewind point data.
type TemporaryCheckpointInfo struct {
	// CommitHash is the hash of the checkpoint commit
	CommitHash plumbing.Hash

	// Message is the first line of the commit message
	Message string

	// SessionID is the session identifier from the Entire-Session trailer
	SessionID string

	// MetadataDir is the metadata directory path from trailers
	MetadataDir string

	// IsTaskCheckpoint indicates if this is a task checkpoint
	IsTaskCheckpoint bool

	// ToolUseID is the tool use ID for task checkpoints
	ToolUseID string

	// Timestamp is when the checkpoint was created
	Timestamp time.Time
}

