 238→	obj.SetType(plumbing.TreeObject)
 239→	if err := tree.Encode(obj); err != nil {
 240→		t.Fatalf("failed to encode tree: %v", err)
 241→	}
 242→
 243→	hash, err := storage.SetEncodedObject(obj)
 244→	if err != nil {
 245→		t.Fatalf("failed to store tree: %v", err)
 246→	}
 247→
 248→	// Retrieve the tree
 249→	treeObj, err := object.GetTree(storage, hash)
 250→	if err != nil {
 251→		t.Fatalf("failed to get tree: %v", err)
 252→	}
 253→
 254→	return treeObj
 255→}
