 766→// TestGetAllChangedFilesBetweenTrees tests the hash-based file change detection.
 767→func TestGetAllChangedFilesBetweenTrees(t *testing.T) {
 768→	storer := memory.NewStorage()
 769→
 770→	// Helper to create a blob and return its hash
 771→	//nolint:errcheck // Test helper - errors would cause test failures anyway
 772→	createBlob := func(content string) plumbing.Hash {
 773→		blob := storer.NewEncodedObject()
 774→		blob.SetType(plumbing.BlobObject)
 775→		writer, _ := blob.Writer()
 776→		_, _ = writer.Write([]byte(content))
 777→		_ = writer.Close()
 778→		hash, _ := storer.SetEncodedObject(blob)
 779→		return hash
 780→	}
 781→
 782→	// Helper to create a tree from file entries
 783→	//nolint:errcheck // Test helper - errors would cause test failures anyway
 784→	createTree := func(files map[string]string) *object.Tree {
 785→		var entries []object.TreeEntry
