 185→// buildTestTree creates an object.Tree from a map of file paths to content.
 186→// This is a test helper for creating trees without a full git repository.
 187→func buildTestTree(t *testing.T, files map[string]string) *object.Tree {
 188→	t.Helper()
 189→
 190→	if len(files) == 0 {
 191→		return nil
 192→	}
 193→
 194→	// Use memory storage to build a tree
 195→	storage := memory.NewStorage()
 196→
 197→	// Create blob objects for each file
 198→	var entries []object.TreeEntry
 199→	for path, content := range files {
 200→		// Encode the blob
 201→		obj := storage.NewEncodedObject()
 202→		obj.SetType(plumbing.BlobObject)
 203→		writer, err := obj.Writer()
 204→		if err != nil {
 205→			t.Fatalf("failed to create blob writer: %v", err)
 206→		}
 207→		if _, err := writer.Write([]byte(content)); err != nil {
 208→			t.Fatalf("failed to write blob content: %v", err)
 209→		}
 210→		writer.Close()
 211→
 212→		// Store the blob
 213→		hash, err := storage.SetEncodedObject(obj)
 214→		if err != nil {
 215→			t.Fatalf("failed to store blob: %v", err)
 216→		}
 217→
 218→		// Create tree entry
 219→		entries = append(entries, object.TreeEntry{
 220→			Name: path,
 221→			Mode: 0o100644,
 222→			Hash: hash,
 223→		})
 224→	}
 225→
 226→	// Sort entries by name (required by git tree format)
 227→	sort.Slice(entries, func(i, j int) bool {
 228→		return entries[i].Name < entries[j].Name
 229→	})
 230→
 231→	// Create the tree
 232→	tree := &object.Tree{
 233→		Entries: entries,
 234→	}
 235→
 236→	// Encode and store the tree
 237→	obj := storage.NewEncodedObject()
 238→	obj.SetType(plumbing.TreeObject)
 239→	if err := tree.Encode(obj); err != nil {
 240→		t.Fatalf("failed to encode tree: %v", err)
 241→	}
 242→
 243→	hash, err := storage.SetEncodedObject(obj)
 244→	if err != nil {
 245→		t.Fatalf("failed to store tree: %v", err)
 246→	}
 247→
 248→	// Retrieve the tree
 249→	treeObj, err := object.GetTree(storage, hash)
 250→	if err != nil {
 251→		t.Fatalf("failed to get tree: %v", err)
 252→	}
 253→
 254→	return treeObj
 255→}
