 677→// TestCalculateAttributionWithAccumulated_UserEditsNonAgentFile tests the bug where
 678→// post-checkpoint user edits to files the agent never touched are undercounted.
 679→//
 680→// Bug scenario:
 681→//  1. Agent touches file1.go (added to filesTouched)
 682→//  2. User edits file2.go between checkpoints → captured in PromptAttributions
 683→//  3. User edits file2.go again AFTER last checkpoint, before commit
 684→//  4. BUG: Post-checkpoint calculation only looks at filesTouched (file1.go),
 685→//     missing the file2.go edits in step 3
 686→//
 687→// This causes undercounted user contributions and inflated agent percentage.
 688→func TestCalculateAttributionWithAccumulated_UserEditsNonAgentFile(t *testing.T) {
 689→	// Base: two files
 690→	baseTree := buildTestTree(t, map[string]string{
 691→		"file1.go": "package main\n",
 692→		"file2.go": "package util\n",
 693→	})
 694→
 695→	// Shadow (agent work): agent adds to file1.go only
 696→	// file2.go is NOT in shadow tree because it's not in filesTouched
 697→	shadowTree := buildTestTree(t, map[string]string{
 698→		"file1.go": "package main\n\nfunc agent1() {}\nfunc agent2() {}\n",
 699→	})
 700→
 701→	// Head (final commit): user adds more to file2.go AFTER last checkpoint
 702→	// file2.go has: 1 base line + 2 accumulated + 2 post-checkpoint = 5 lines total
 703→	headTree := buildTestTree(t, map[string]string{
 704→		"file1.go": "package main\n\nfunc agent1() {}\nfunc agent2() {}\n",
 705→		"file2.go": "package util\n\n// User edit 1\n// User edit 2\n// User edit 3\n",
 706→	})
 707→
 708→	// filesTouched only includes file1.go (agent-touched)
 709→	filesTouched := []string{"file1.go"}
 710→
 711→	// PromptAttributions captured user edits to file2.go between checkpoints
 712→	promptAttributions := []PromptAttribution{
 713→		{
 714→			CheckpointNumber: 1,
 715→			UserLinesAdded:   2, // User edit 1, 2 (between checkpoints)
 716→			UserLinesRemoved: 0,
 717→			UserAddedPerFile: map[string]int{"file2.go": 2}, // Tracks which file the edits were in
 718→		},
 719→	}
 720→
 721→	result := CalculateAttributionWithAccumulated(
 722→		baseTree, shadowTree, headTree, filesTouched, promptAttributions,
 723→	)
 724→
 725→	if result == nil {
 726→		t.Fatal("expected non-nil result")
 727→	}
 728→
 729→	// Expected calculation:
 730→	// - Agent added 3 lines to file1.go (2 functions + 1 blank)
 731→	// - User added 2 lines to file2.go between checkpoints (from PromptAttribution)
 732→	// - User added 2 MORE lines to file2.go after last checkpoint (post-checkpoint)
 733→	// - Total user added: 2 + 2 = 4
 734→	// - agentLinesInCommit: 3
 735→	// - Total: 3 + 4 = 7
 736→	// - Agent percentage: 3/7 = 42.9%
 737→	//
 738→	// BUG (if not fixed): Post-checkpoint calculation only looks at file1.go,
 739→	// so it would miss the 2 post-checkpoint edits to file2.go:
 740→	// - Total user added: 2 + 0 = 2 (WRONG)
 741→	// - Total: 3 + 2 = 5 (WRONG)
 742→	// - Agent percentage: 3/5 = 60% (WRONG, inflated)
 743→
 744→	t.Logf("Attribution: agent=%d, human_added=%d, total=%d, percentage=%.1f%%",
 745→		result.AgentLines, result.HumanAdded, result.TotalCommitted, result.AgentPercentage)
 746→
 747→	if result.AgentLines != 3 {
 748→		t.Errorf("AgentLines = %d, want 3", result.AgentLines)
 749→	}
 750→
 751→	if result.HumanAdded != 4 {
 752→		t.Errorf("HumanAdded = %d, want 4 (2 between + 2 post-checkpoint, including file agent never touched)",
 753→			result.HumanAdded)
 754→	}
 755→
 756→	if result.TotalCommitted != 7 {
 757→		t.Errorf("TotalCommitted = %d, want 7 (3 agent + 4 user)", result.TotalCommitted)
 758→	}
 759→
 760→	// Agent percentage should be 3/7 = 42.9%
 761→	if result.AgentPercentage < 42.8 || result.AgentPercentage > 43.0 {
 762→		t.Errorf("AgentPercentage = %.1f%%, want ~42.9%% (not inflated)", result.AgentPercentage)
 763→	}
 764→}
