 766→// TestGetAllChangedFilesBetweenTrees tests the hash-based file change detection.
 767→func TestGetAllChangedFilesBetweenTrees(t *testing.T) {
 768→	storer := memory.NewStorage()
 769→
 770→	// Helper to create a blob and return its hash
 771→	//nolint:errcheck // Test helper - errors would cause test failures anyway
 772→	createBlob := func(content string) plumbing.Hash {
 773→		blob := storer.NewEncodedObject()
 774→		blob.SetType(plumbing.BlobObject)
 775→		writer, _ := blob.Writer()
 776→		_, _ = writer.Write([]byte(content))
 777→		_ = writer.Close()
 778→		hash, _ := storer.SetEncodedObject(blob)
 779→		return hash
 780→	}
 781→
 782→	// Helper to create a tree from file entries
 783→	//nolint:errcheck // Test helper - errors would cause test failures anyway
 784→	createTree := func(files map[string]string) *object.Tree {
 785→		var entries []object.TreeEntry
 786→		for name, content := range files {
 787→			entries = append(entries, object.TreeEntry{
 788→				Name: name,
 789→				Mode: 0o100644,
 790→				Hash: createBlob(content),
 791→			})
 792→		}
 793→		// Sort entries by name (git requirement)
 794→		sort.Slice(entries, func(i, j int) bool {
 795→			return entries[i].Name < entries[j].Name
 796→		})
 797→
 798→		tree := &object.Tree{Entries: entries}
 799→		treeObj := storer.NewEncodedObject()
 800→		_ = tree.Encode(treeObj)
 801→		hash, _ := storer.SetEncodedObject(treeObj)
 802→
 803→		// Re-decode to get proper Tree object with hash
 804→		decodedTree, _ := object.GetTree(storer, hash)
 805→		return decodedTree
 806→	}
 807→
 808→	t.Run("both trees nil", func(t *testing.T) {
 809→		result := getAllChangedFilesBetweenTrees(nil, nil)
 810→		if result != nil {
 811→			t.Errorf("expected nil, got %v", result)
 812→		}
 813→	})
 814→
 815→	t.Run("tree1 nil (all files added)", func(t *testing.T) {
 816→		tree2 := createTree(map[string]string{
 817→			testFile1:  "content1",
 818→			"file2.go": "content2",
 819→		})
 820→
 821→		result := getAllChangedFilesBetweenTrees(nil, tree2)
 822→		sort.Strings(result)
 823→
 824→		if len(result) != 2 {
 825→			t.Fatalf("expected 2 changed files, got %d: %v", len(result), result)
 826→		}
 827→		if result[0] != testFile1 || result[1] != "file2.go" {
 828→			t.Errorf("expected [file1.go, file2.go], got %v", result)
 829→		}
 830→	})
 831→
 832→	t.Run("tree2 nil (all files deleted)", func(t *testing.T) {
 833→		tree1 := createTree(map[string]string{
 834→			testFile1: "content1",
 835→		})
 836→
 837→		result := getAllChangedFilesBetweenTrees(tree1, nil)
 838→
 839→		if len(result) != 1 || result[0] != testFile1 {
 840→			t.Errorf("expected [file1.go], got %v", result)
 841→		}
 842→	})
 843→
 844→	t.Run("identical trees (no changes)", func(t *testing.T) {
