	)

	if result == nil {
		t.Fatal("expected non-nil result")
	}

	// Expected:
	// - Agent added 8 lines (base → shadow)
	// - User added 2 lines (shadow → head)
	// - No removals or modifications
	// - Total = 8 + 2 = 10
	// - Agent percentage = 8/10 = 80%

	if result.AgentLines != 8 {
