	// - Agent added 10 lines (base → shadow)
	// - User added 2 lines, removed 5 lines (shadow → head)
	// - humanModified = min(2, 5) = 2
	// - pureUserAdded = 2 - 2 = 0
	// - pureUserRemoved = 5 - 2 = 3
	// - agentLinesInCommit = 10 - 3 - 2 = 5
	// - Total = 10 + 0 - 3 = 7
