	// Create tree entry
	entries = append(entries, object.TreeEntry{
		Name: path,
		Mode: 0o100644,
		Hash: hash,
	})
}

// Sort entries by name (required by git tree format)
sort.Slice(entries, func(i, j int) bool {
	return entries[i].Name < entries[j].Name
})

// Create the tree
tree := &object.Tree{
	Entries: entries,
