func TestShadowStrategy_Registration(t *testing.T) {
	s, err := Get(StrategyNameManualCommit)
	if err != nil {
		t.Fatalf("Get(%q) error = %v", StrategyNameManualCommit, err)
	}
	if s == nil {
		t.Fatal("Get() returned nil strategy")
	}
